            AVStereo3D *stereo = av_stereo3d_create_side_data(s->cur_pic.ptr->f);
            if (!stereo)
                return AVERROR(ENOMEM);

            stereo->type = s1->stereo3d_type;
            s1->has_stereo3d = 0;
