{
    int ret;
    int nb_channels = 0;
    AVChannelCustom *map = NULL;
    AVChannelCustom custom = {0};

    while (*str) {
        char *channel, *chname;
        ret = av_opt_get_key_value(&str, "@", "+", AV_OPT_FLAG_IMPLICIT_KEY, &channel, &chname);
        if (ret < 0) {
            av_freep(&map);
            return ret;
        }
